import { describe, it } from "node:test";
import assert from "node:assert";
import {
  generateRunId, initRunDir, writeState, readState,
  writeStepOutput, buildResult, formatResult, aggregateUsage,
} from "./state.ts";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";
import type { ExecutionState, WorkflowSpec, StepResult, StepUsage } from "./types.ts";

describe("generateRunId", () => {
  it("includes workflow name", () => {
    const id = generateRunId("bugfix");
    assert.ok(id.startsWith("bugfix-"));
  });

  it("generates unique IDs", () => {
    const a = generateRunId("test");
    const b = generateRunId("test");
    assert.notStrictEqual(a, b);
  });
});

describe("initRunDir", () => {
  it("creates directory structure", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-state-"));
    const runDir = initRunDir(tmpDir, "test-run-1");

    assert.ok(fs.existsSync(runDir));
    assert.ok(fs.existsSync(path.join(runDir, "sessions")));
    assert.ok(fs.existsSync(path.join(runDir, "outputs")));

    fs.rmSync(tmpDir, { recursive: true });
  });
});

describe("writeState / readState", () => {
  it("round-trips execution state", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-state-"));
    const runDir = path.join(tmpDir, "run");
    fs.mkdirSync(runDir, { recursive: true });

    const state: ExecutionState = {
      input: { description: "test" },
      steps: {},
      status: "running",
    };

    writeState(runDir, state);
    const loaded = readState(runDir);
    assert.deepStrictEqual(loaded, state);

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("returns null for nonexistent state", () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-state-"));
    assert.strictEqual(readState(tmpDir), null);
    fs.rmSync(tmpDir, { recursive: true });
  });
});

describe("aggregateUsage", () => {
  it("sums usage across steps", () => {
    const usage = (n: number): StepUsage => ({
      input: n * 100, output: n * 50, cacheRead: 0, cacheWrite: 0,
      cost: n * 0.01, turns: n,
    });
    const steps: Record<string, StepResult> = {
      a: { step: "a", agent: "x", status: "completed", usage: usage(1), durationMs: 1000 },
      b: { step: "b", agent: "y", status: "completed", usage: usage(2), durationMs: 2000 },
    };
    const total = aggregateUsage(steps);
    assert.strictEqual(total.input, 300);
    assert.strictEqual(total.output, 150);
    assert.strictEqual(total.turns, 3);
    assert.ok(Math.abs(total.cost - 0.03) < 0.001);
  });
});

describe("formatResult", () => {
  it("includes workflow name and step summary", () => {
    const result = buildResult(
      { name: "test", steps: { s: { agent: "a" } } } as WorkflowSpec,
      "test-run-1",
      "/tmp/run",
      {
        input: {},
        steps: {
          s: {
            step: "s", agent: "a", status: "completed",
            textOutput: "done",
            usage: { input: 100, output: 50, cacheRead: 0, cacheWrite: 0, cost: 0.01, turns: 1 },
            durationMs: 5000,
          },
        },
        status: "completed",
      },
      "completed",
    );
    const text = formatResult(result);
    assert.ok(text.includes("test"));
    assert.ok(text.includes("completed"));
    assert.ok(text.includes("$0.01") || text.includes("0.01"));
  });
});

import { describe, it } from "node:test";
import assert from "node:assert";
import { executeWorkflow } from "./workflow-executor.ts";
import type { WorkflowSpec, AgentSpec, ExecutionState } from "./types.ts";
import fs from "node:fs";
import path from "node:path";
import os from "node:os";

// Mock ExtensionContext and ExtensionAPI for testing
function mockCtx(cwd: string) {
  return {
    cwd,
    hasUI: false,
    ui: {
      setWidget: () => {},
      notify: () => {},
      setStatus: () => {},
    },
    // ... other ctx fields as needed (most unused in headless mode)
  } as any;
}

function mockPi() {
  const messages: any[] = [];
  return {
    sendMessage: (msg: any, opts: any) => messages.push({ msg, opts }),
    _messages: messages,
  } as any;
}

// Skip if pi is not available
let hasPi = false;
try {
  const { execSync } = await import("node:child_process");
  execSync("pi --version", { stdio: "ignore" });
  hasPi = true;
} catch {}

describe("executeWorkflow", { skip: !hasPi ? "pi not available" : undefined }, () => {
  it("runs a single-step workflow", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test workflow",
      steps: {
        greet: { agent: "default" },
      },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    const pi = mockPi();
    const result = await executeWorkflow(spec, {}, {
      ctx: mockCtx(tmpDir),
      pi,
      loadAgent: () => ({ name: "default" }),
    });

    assert.strictEqual(result.status, "completed");
    assert.ok(result.steps.greet);
    assert.strictEqual(result.steps.greet.status, "completed");
    assert.ok(result.totalDurationMs > 0);
    assert.ok(pi._messages.length >= 1); // sendMessage called

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 60000 });

  it("fails fast on step failure", async () => {
    // Use a pre-aborted signal to reliably trigger failure on the first step.
    // pi does not necessarily fail for unknown agent names, so the original
    // approach of using a nonexistent agent is not reliable. An already-aborted
    // signal exercises the executor's cancellation/fail-fast path: the first
    // step is marked failed with "Workflow cancelled" and the second step
    // is never reached.
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test",
      steps: {
        willFail: { agent: "default" },
        shouldNotRun: { agent: "default" },
      },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    const controller = new AbortController();
    controller.abort(); // pre-abort

    const result = await executeWorkflow(spec, {}, {
      ctx: mockCtx(tmpDir),
      pi: mockPi(),
      signal: controller.signal,
      loadAgent: () => ({ name: "default" }),
    });

    assert.strictEqual(result.status, "failed");
    assert.ok(result.steps.willFail);
    assert.strictEqual(result.steps.willFail.error, "Workflow cancelled");
    assert.ok(!result.steps.shouldNotRun); // never executed

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 30000 });

  it("validates workflow input", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test",
      input: {
        type: "object",
        required: ["name"],
        properties: { name: { type: "string" } },
      },
      steps: { s: { agent: "default" } },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    await assert.rejects(
      () => executeWorkflow(spec, { name: 123 }, {
        ctx: mockCtx(tmpDir),
        pi: mockPi(),
        loadAgent: () => ({ name: "default" }),
      }),
      (err: unknown) => err instanceof Error && err.message.includes("Validation failed"),
    );

    fs.rmSync(tmpDir, { recursive: true });
  });

  it("resolves expressions between steps", async () => {
    // This test verifies that step 2 can reference step 1's output.
    // Since we can't easily control what pi outputs, we verify the
    // expression resolution doesn't throw and both steps complete.
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test",
      steps: {
        first: { agent: "default" },
        second: {
          agent: "default",
          input: { prior: "${{ steps.first.textOutput }}" },
        },
      },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    const result = await executeWorkflow(spec, {}, {
      ctx: mockCtx(tmpDir),
      pi: mockPi(),
      loadAgent: () => ({ name: "default" }),
    });

    assert.strictEqual(result.status, "completed");
    assert.strictEqual(Object.keys(result.steps).length, 2);

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 120000 });

  it("persists state to disk", async () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "wf-exec-"));
    const spec: WorkflowSpec = {
      name: "test",
      description: "test",
      steps: { s: { agent: "default" } },
      source: "project",
      filePath: path.join(tmpDir, "test.workflow.yaml"),
    };

    const result = await executeWorkflow(spec, {}, {
      ctx: mockCtx(tmpDir),
      pi: mockPi(),
      loadAgent: () => ({ name: "default" }),
    });

    // Verify state.json exists in run directory
    const stateFile = path.join(result.runDir, "state.json");
    assert.ok(fs.existsSync(stateFile));
    const savedState = JSON.parse(fs.readFileSync(stateFile, "utf-8"));
    assert.strictEqual(savedState.status, "completed");

    fs.rmSync(tmpDir, { recursive: true });
  }, { timeout: 60000 });
});

